-- Read-only P7 verification. Replace UUIDs before running.
select mode,outbound_enabled,inbound_enabled,kill_switch_enabled,max_attempts,lease_seconds,initial_retry_seconds,max_retry_seconds,replay_window_seconds,max_inbound_bytes,revision,created_at from public.conveyancer_provider_transport_controls where organisation_id='00000000-0000-0000-0000-000000000000'::uuid and attorney_firm_id='00000000-0000-0000-0000-000000000000'::uuid order by revision desc limit 5;
select status,count(*) from public.conveyancer_provider_outbound_commands where organisation_id='00000000-0000-0000-0000-000000000000'::uuid and attorney_firm_id='00000000-0000-0000-0000-000000000000'::uuid group by status order by status;
select status,count(*) from public.conveyancer_provider_inbound_envelopes where organisation_id='00000000-0000-0000-0000-000000000000'::uuid and attorney_firm_id='00000000-0000-0000-0000-000000000000'::uuid group by status order by status;
select direction,event_type,detail,occurred_at from public.conveyancer_provider_transport_receipts where organisation_id='00000000-0000-0000-0000-000000000000'::uuid and attorney_firm_id='00000000-0000-0000-0000-000000000000'::uuid order by occurred_at desc limit 100;
